/**
 * Test case to reproduce the bug: url_encode should support specifying character sets
 */
public class UrlEncodeCharsetTest {

    public static void main(String[] args) {
        System.out.println("Testing current url_encode function limitations:");

        // Test 1: Current implementation only uses UTF-8
        try {
            String testString = "测试中文";
            String encodedUTF8 = java.net.URLEncoder.encode(testString, java.nio.charset.StandardCharsets.UTF_8);
            String encodedGBK = java.net.URLEncoder.encode(testString, "GBK");

            System.out.println("Original string: " + testString);
            System.out.println("UTF-8 encoded: " + encodedUTF8);
            System.out.println("GBK encoded: " + encodedGBK);
            System.out.println("Are they different? " + !encodedUTF8.equals(encodedGBK));

        } catch (Exception e) {
            e.printStackTrace();
        }

        System.out.println("\nExpected behavior: url_encode should support optional charset parameter");
        System.out.println("Example: url_encode('测试中文', 'GBK') should use GBK encoding");
        System.out.println("Example: url_encode('测试中文') should use UTF-8 encoding (default)");
    }
}

