package org.apache.inlong.sdk.transform.process.function.string;

import org.apache.inlong.sdk.transform.decode.SourceDecoderFactory;
import org.apache.inlong.sdk.transform.encode.SinkEncoderFactory;
import org.apache.inlong.sdk.transform.pojo.TransformConfig;
import org.apache.inlong.sdk.transform.process.TransformProcessor;

import org.junit.Assert;
import org.junit.Test;

import java.util.HashMap;
import java.util.List;

public class TestUrlEncodeCharset extends AbstractFunctionStringTestBase {

    @Test
    public void testUrlEncodeWithCharset() throws Exception {
        // Current limitation: url_encode only supports UTF-8, no charset parameter

        // Test 1: Basic UTF-8 encoding (current functionality)
        String transformSql1 = "select url_encode(string1) from source";
        TransformConfig config1 = new TransformConfig(transformSql1);
        TransformProcessor<String, String> processor1 = TransformProcessor
                .create(config1, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output1 = processor1.transform("https://example.com/search?q=\u6d4b\u8bd5|banana|cloud|1",
                new HashMap<>());
        Assert.assertEquals(1, output1.size());
        // Expected UTF-8 encoded result
        Assert.assertEquals(output1.get(0), "result=https%3A%2F%2Fexample.com%2Fsearch%3Fq%3D%E6%B5%8B%E8%AF%95");

        // Test 2: Current implementation cannot handle different charsets
        // This should fail because charset parameter is not supported
        try {
            String transformSql2 = "select url_encode(string1, 'GBK') from source";
            TransformConfig config2 = new TransformConfig(transformSql2);
            // This will likely fail since charset parameter is not implemented
            Assert.fail("Charset parameter should not be supported in current implementation");
        } catch (Exception e) {
            // Expected - charset parameter is not supported yet
            System.out.println("Expected error: " + e.getMessage());
