                "https%3A%2F%2Fexample.com%2Fsearch%3Fq%3D%E6%B5%8B%E8%AF%95|banana|cloud|1",
                new HashMap<>());
        Assert.assertEquals(1, output1.size());
        // Expected UTF-8 decoded result
        Assert.assertEquals(output1.get(0), "result=https://example.com/search?q=\u6d4b\u8bd5");

        // Test 2: Current implementation cannot handle different charsets
